import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../api/axiosConfig';
import toast from 'react-hot-toast';
import { UserPlus, Mail, Lock, User, Activity } from 'lucide-react';

const RegisterPage = () => {
  const [data, setData] = useState({
    fullName: '',
    email: '',
    password: ''
  });
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleRegister = async (e) => {
    e.preventDefault();
    
    if (!data.fullName || !data.email || !data.password) {
      toast.error('ALL_FIELDS_REQUIRED');
      return;
    }

    const toastId = toast.loading('INITIALIZING_IDENTITY_NODE...');
    setLoading(true);
    
    try {
      await api.post('/auth/register', data);
      toast.success('IDENTITY_INITIALIZED: ACCESS_GRANTED', { id: toastId });
      navigate('/login');
    } catch (err) {
      toast.error('GATE_REJECTION: REGISTRATION_FAILED', { id: toastId });
    } finally {
      setLoading(false);
    }
  };

  return (
    /* 🎯 FIX: flex items-center justify-center forces the card to the middle of the screen */
    <div className="min-h-[85vh] w-full flex flex-col items-center justify-center py-12 px-4 reveal-data">
      
      {/* 🏛️ The Terminal Card: Centralized layout with institutional padding */}
      <div className="w-full max-w-md terminal-card relative overflow-hidden shadow-2xl">
        
        {/* Ambient Glow matching your Cyber Theme logic */}
        <div className="absolute top-0 left-0 w-full h-[1px] bg-emerald-500/40 shadow-[0_0_15px_var(--accent-glow)] animate-scan" />

        <div className="text-center mb-10">
          <div className="flex justify-center mb-6 text-emerald-500">
            <UserPlus size={42} className="animate-pulse" />
          </div>
          <h1 className="text-3xl font-light tracking-tight text-white mb-2 uppercase">
            Initialize_Node
          </h1>
          <p className="text-[10px] text-white/40 text-[10px] uppercase tracking-[0.25em] font-mono">
            Identity Setup // System_V3.0_Core
          </p>
        </div>

        <form onSubmit={handleRegister} className="space-y-5">
          {/* Full Name Field */}
          <div className="space-y-2">
            <label className="flex items-center gap-2 text-[10px] text-emerald-500 font-bold uppercase tracking-widest ml-1">
              <User size={12} /> Full_Identity
            </label>
            <input
              type="text"
              className="terminal-input"
              placeholder="Operator Name"
              value={data.fullName}
              onChange={(e) => setData({ ...data, fullName: e.target.value })}
              required
            />
          </div>

          {/* Email Field */}
          <div className="space-y-2">
            <label className="flex items-center gap-2 text-[10px] text-emerald-500 font-bold uppercase tracking-widest ml-1">
              <Mail size={12} /> Registry_Email
            </label>
            <input
              type="email"
              className="terminal-input"
              placeholder="operator@finify.ai"
              value={data.email}
              onChange={(e) => setData({ ...data, email: e.target.value })}
              required
            />
          </div>

          {/* Password Field */}
          <div className="space-y-2">
            <label className="flex items-center gap-2 text-[10px] text-emerald-500 font-bold uppercase tracking-widest ml-1">
              <Lock size={12} /> Security_Key
            </label>
            <input
              type="password"
              className="terminal-input"
              placeholder="••••••••"
              value={data.password}
              onChange={(e) => setData({ ...data, password: e.target.value })}
              required
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            className={`emerald-btn mt-8 w-full ${loading ? 'opacity-60 cursor-not-allowed' : 'hover:scale-[1.01]'}`}
          >
            {loading ? (
              <Activity size={16} className="animate-spin" />
            ) : (
              'Initialize_New_Identity'
            )}
          </button>
        </form>

        <div className="mt-10 pt-8 border-t border-white/5 text-center">
          <p className="text-[10px] text-white/30 uppercase tracking-[0.25em]">
            Identity already exists?{' '}
            <Link to="/login" className="text-emerald-500 underline hover:text-emerald-400 transition-colors">
              Access_Gate
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
};

export default RegisterPage;
